package com.example.search.service;

import com.example.search.model.Product;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.ElasticsearchStatusException;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.client.indices.PutMappingRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.HashMap;
import java.util.Map;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final String productIndex;

    public ProductIndexService(RestHighLevelClient client,
                              ObjectMapper objectMapper,
                              @Value("${elasticsearch.index.products:products}") String productIndex) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.productIndex = productIndex;
    }

    public void ensureProductIndex() throws IOException {
        GetIndexRequest getIndexRequest = new GetIndexRequest(productIndex);
        boolean exists = client.indices().exists(getIndexRequest, RequestOptions.DEFAULT);
        if (exists) return;

        CreateIndexRequest request = new CreateIndexRequest(productIndex);
        request.settings(Settings.builder()
                .put("index.number_of_shards", 1)
                .put("index.number_of_replicas", 0)
                .put("analysis.analyzer.folded.tokenizer", "standard")
                .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding")
                .put("analysis.analyzer.edge.tokenizer", "standard")
                .putList("analysis.analyzer.edge.filter", "lowercase", "asciifolding", "edge_ngram_filter")
                .put("analysis.filter.edge_ngram_filter.type", "edge_ngram")
                .put("analysis.filter.edge_ngram_filter.min_gram", 2)
                .put("analysis.filter.edge_ngram_filter.max_gram", 20)
        );

        String mapping = "{\n" +
                "  \"dynamic\": true,\n" +
                "  \"properties\": {\n" +
                "    \"id\": {\"type\": \"keyword\"},\n" +
                "    \"sku\": {\"type\": \"keyword\"},\n" +
                "    \"name\": {\n" +
                "      \"type\": \"text\",\n" +
                "      \"analyzer\": \"folded\",\n" +
                "      \"fields\": {\n" +
                "        \"keyword\": {\"type\": \"keyword\", \"ignore_above\": 256},\n" +
                "        \"edge\": {\"type\": \"text\", \"analyzer\": \"edge\"}\n" +
                "      }\n" +
                "    },\n" +
                "    \"description\": {\"type\": \"text\", \"analyzer\": \"folded\"},\n" +
                "    \"brand\": {\"type\": \"keyword\"},\n" +
                "    \"categories\": {\"type\": \"keyword\"},\n" +
                "    \"tags\": {\"type\": \"keyword\"},\n" +
                "    \"price\": {\"type\": \"double\"},\n" +
                "    \"currency\": {\"type\": \"keyword\"},\n" +
                "    \"inStock\": {\"type\": \"boolean\"},\n" +
                "    \"rating\": {\"type\": \"double\"},\n" +
                "    \"reviewsCount\": {\"type\": \"long\"},\n" +
                "    \"createdAt\": {\"type\": \"date\"},\n" +
                "    \"updatedAt\": {\"type\": \"date\"},\n" +
                "    \"attributes\": {\"type\": \"object\", \"dynamic\": true}\n" +
                "  }\n" +
                "}";
        request.mapping(mapping, XContentType.JSON);

        client.indices().create(request, RequestOptions.DEFAULT);
    }

    public void deleteProductIndex() throws IOException {
        try {
            AcknowledgedResponse resp = client.indices().delete(new DeleteIndexRequest(productIndex), RequestOptions.DEFAULT);
        } catch (ElasticsearchStatusException e) {
            // ignore missing
        }
    }

    public void putProductMapping() throws IOException {
        PutMappingRequest request = new PutMappingRequest(productIndex);
        String mapping = "{\n" +
                "  \"properties\": {\n" +
                "    \"attributes\": {\"type\": \"object\", \"dynamic\": true}\n" +
                "  }\n" +
                "}";
        request.source(mapping, XContentType.JSON);
        client.indices().putMapping(request, RequestOptions.DEFAULT);
    }

    public String indexProduct(Product product) throws IOException {
        if (product.getCreatedAt() == null) product.setCreatedAt(Instant.now());
        product.setUpdatedAt(Instant.now());

        Map<String, Object> src = toMap(product);
        String id = product.getId();
        if (id == null || id.isBlank()) {
            id = product.getSku();
        }

        IndexRequest req = new IndexRequest(productIndex).id(id).source(src);
        client.index(req, RequestOptions.DEFAULT);
        return id;
    }

    private Map<String, Object> toMap(Product product) throws JsonProcessingException {
        return objectMapper.convertValue(product, Map.class);
    }

    public String getProductIndex() {
        return productIndex;
    }
}

package com.example.search.service;

import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final String productIndex;
    private final String queryIndex;

    public ProductSearchService(RestHighLevelClient client,
                                ObjectMapper objectMapper,
                                @Value("${elasticsearch.index.products:products}") String productIndex,
                                @Value("${elasticsearch.index.queries:search_queries}") String queryIndex) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.productIndex = productIndex;
        this.queryIndex = queryIndex;
    }

    public SearchResponseDto search(SearchRequestDto req) throws IOException {
        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 20 : Math.min(200, Math.max(1, req.getSize()));

        SearchSourceBuilder ssb = new SearchSourceBuilder();
        ssb.from(page * size);
        ssb.size(size);
        ssb.trackTotalHits(true);

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        String q = req.getQ();
        if (q != null && !q.isBlank()) {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q, "name^4", "name.edge^2", "description", "brand^2", "categories^2", "tags", "attributes.*")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness("AUTO");
            bool.must(mm);
        } else {
            bool.must(QueryBuilders.matchAllQuery());
        }

        if (req.getInStock() != null) {
            bool.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }

        if (req.getMinPrice() != null || req.getMaxPrice() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (req.getMinPrice() != null) range.gte(req.getMinPrice());
            if (req.getMaxPrice() != null) range.lte(req.getMaxPrice());
            bool.filter(range);
        }

        if (req.getTermsFilters() != null) {
            for (Map.Entry<String, List<String>> e : req.getTermsFilters().entrySet()) {
                String field = e.getKey();
                List<String> values = e.getValue();
                if (field == null || field.isBlank() || values == null || values.isEmpty()) continue;
                String normalizedField = normalizeFacetField(field);
                bool.filter(QueryBuilders.termsQuery(normalizedField, values));
            }
        }

        ssb.query(bool);

        String sort = req.getSort();
        if ("price_asc".equalsIgnoreCase(sort)) {
            ssb.sort("price", SortOrder.ASC);
        } else if ("price_desc".equalsIgnoreCase(sort)) {
            ssb.sort("price", SortOrder.DESC);
        } else if ("newest".equalsIgnoreCase(sort)) {
            ssb.sort("createdAt", SortOrder.DESC);
        }

        ssb.aggregation(AggregationBuilders.terms("facet_brand").field("brand").size(50));
        ssb.aggregation(AggregationBuilders.terms("facet_categories").field("categories").size(50));
        ssb.aggregation(AggregationBuilders.terms("facet_tags").field("tags").size(50));
        ssb.aggregation(AggregationBuilders.terms("facet_inStock").field("inStock").size(10));

        SearchRequest searchRequest = new SearchRequest(productIndex).source(ssb);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> items = Arrays.stream(response.getHits().getHits())
                .map(this::toProduct)
                .collect(Collectors.toList());

        long total = response.getHits().getTotalHits() == null ? items.size() : response.getHits().getTotalHits().value;

        Map<String, List<SearchResponseDto.FacetBucket>> facets = new LinkedHashMap<>();
        facets.put("brand", termsToBuckets((Terms) response.getAggregations().get("facet_brand")));
        facets.put("categories", termsToBuckets((Terms) response.getAggregations().get("facet_categories")));
        facets.put("tags", termsToBuckets((Terms) response.getAggregations().get("facet_tags")));
        facets.put("inStock", termsToBuckets((Terms) response.getAggregations().get("facet_inStock")));

        logQuery(req, total);

        return new SearchResponseDto(items, total, page, size, facets);
    }

    private void logQuery(SearchRequestDto req, long totalHits) {
        try {
            SearchQueryLog log = new SearchQueryLog();
            log.setId(UUID.randomUUID().toString());
            log.setSessionId(req.getSessionId());
            log.setUserId(req.getUserId());
            log.setQuery(req.getQ());
            Map<String, Object> filters = new HashMap<>();
            if (req.getTermsFilters() != null) filters.put("termsFilters", req.getTermsFilters());
            if (req.getMinPrice() != null) filters.put("minPrice", req.getMinPrice());
            if (req.getMaxPrice() != null) filters.put("maxPrice", req.getMaxPrice());
            if (req.getInStock() != null) filters.put("inStock", req.getInStock());
            if (req.getSort() != null) filters.put("sort", req.getSort());
            log.setFilters(filters);
            log.setPage(req.getPage());
            log.setSize(req.getSize());
            log.setTimestamp(Instant.now());
            log.setTotalHits(totalHits);

            Map<String, Object> src = objectMapper.convertValue(log, Map.class);
            IndexRequest indexRequest = new IndexRequest(queryIndex).id(log.getId()).source(src);
            client.index(indexRequest, RequestOptions.DEFAULT);
        } catch (Exception ignored) {
        }
    }

    private List<SearchResponseDto.FacetBucket> termsToBuckets(Terms terms) {
        if (terms == null) return List.of();
        List<SearchResponseDto.FacetBucket> out = new ArrayList<>(terms.getBuckets().size());
        for (Terms.Bucket b : terms.getBuckets()) {
            out.add(new SearchResponseDto.FacetBucket(String.valueOf(b.getKey()), b.getDocCount()));
        }
        return out;
    }

    private Product toProduct(SearchHit hit) {
        Map<String, Object> src = hit.getSourceAsMap();
        Product p = objectMapper.convertValue(src, Product.class);
        if (p.getId() == null || p.getId().isBlank()) p.setId(hit.getId());
        return p;
    }

    private String normalizeFacetField(String field) {
        String f = field.trim();
        if ("category".equalsIgnoreCase(f)) return "categories";
        if ("categories".equalsIgnoreCase(f)) return "categories";
        if ("brand".equalsIgnoreCase(f)) return "brand";
        if ("tags".equalsIgnoreCase(f)) return "tags";
        if ("inStock".equalsIgnoreCase(f)) return "inStock";
        if (f.startsWith("attributes.")) return f;
        if (f.startsWith("attr.")) return "attributes." + f.substring("attr.".length());
        return f;
    }
}

package com.example.search.controller;

import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexService indexService;

    public ProductController(ProductIndexService indexService) {
        this.indexService = indexService;
    }

    @PostMapping("/_ensure-index")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void ensureIndex() throws IOException {
        indexService.ensureProductIndex();
    }

    @PostMapping
    public String indexProduct(@RequestBody Product product) throws IOException {
        indexService.ensureProductIndex();
        return indexService.indexProduct(product);
    }
}

